function out1 = RF_superlorentzian(T2b,chems,w1,delta)%function out1 = RF_superlorentzian(T2b,chems,w1,delta);% t2b is t2 of Gaussian Function% delta is sweep width% Normalized superlorentzian function (works well)% Uses gaussian kernal Scott Swanson University of Michigan % DK note: this equation is legit; it's found for example in Bieri &% Scheffler, MRM 2006f3=0;nend=1000;for ii = 1:nend    stp=1/nend;    ctheta=ii/nend;        f1=T2b*sqrt(2/pi)*(stp).*(abs(-1+3.*(ctheta).^2)).^(-1); %calculate line intensity        f2=exp(-2*(((2*pi*delta-2*pi*chems)*T2b).^2).*((3*(ctheta).^2-1).^(-2))); %calculate line shapes        f3=f1.*f2 + f3; % intensity times shapeend    out1=pi*(w1.^2).*f3; %add RF w1 saturation